#include <stdio.h>
#include <stdlib.h>
#define MAXN 5000
#define MAXM 5000

// Union-find data structure
int parent[MAXN];
int rank[MAXN];

// Function to find the parent of a vertex
int find(int x) {
    if (parent[x] != x) {
        parent[x] = find(parent[x]);
    }
    return parent[x];
}

// Function to union two vertices
void unionSet(int x, int y) {
    int rootX = find(x);
    int rootY = find(y);
    if (rootX != rootY) {
        if (rank[rootX] > rank[rootY]) {
            parent[rootY] = rootX;
        } else if (rank[rootX] < rank[rootY]) {
            parent[rootX] = rootY;
        } else {
            parent[rootY] = rootX;
            rank[rootX]++;
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        // Initialize the union-find data structure
        for (int i = 0; i < N; i++) {
            parent[i] = i;
            rank[i] = 0;
        }
        // Read the edges of L(G)
        int edges[M][2];
        for (int i = 0; i < M; i++) {
            scanf("%d %d", &edges[i][0], &edges[i][1]);
            edges[i][0]--;
            edges[i][1]--;
        }
        // Reconstruct the graph G
        int K = 0;
        int graph[N][2];
        for (int i = 0; i < N; i++) {
            int x = edges[i][0];
            int y = edges[i][1];
            int rootX = find(x);
            int rootY = find(y);
            if (rootX != rootY) {
                graph[K][0] = rootX;
                graph[K][1] = rootY;
                K++;
                unionSet(x, y);
            }
        }
        printf("%d\n", K);
        for (int i = 0; i < K; i++) {
            printf("%d %d\n", graph[i][0] + 1, graph[i][1] + 1);
        }
    }
    return 0;
}

